var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"의외로군.","JPN":"想定の範囲外。","ENG":"This is rather unexpected.","TWN":"真意外啊。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"당연히 <color=#ffd34c>그 사람</color>이 제일 먼저 찾아올 거라고 생각했는데.","JPN":"当然<color=#ffd34c>あの人</color>が真っ先に訪ねてくるだろうと思っていたのだが。","ENG":"I thought naturally <color=#ffd34c>you know who</color> would be the first to visit me.","TWN":"我還以為<color=#ffd34c>那個人</color>會最先來的呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......실망시켜서 유감이군.","JPN":"……残念だったな。","ENG":"Sorry to disappoint.","TWN":"……可惜讓妳失望了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 신입 애송이와 널 만나게 하는 건 아무래도 위험부담이 커서 말이지.","JPN":"でも、新人を貴様に会わせるのはどうしても危険要素が大きいからな。","ENG":"But it’s too risky to let the rookie come see you just yet.","TWN":"畢竟讓妳和新來的小鬼頭見面的風險太大了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"굳이 일부러 문제를 만들 필요는 없으니까.","JPN":"わざわざ災いの元を作る必要もないだろう。","ENG":"No need to make things more difficult than necessary.","TWN":"沒必要刻意製造問題。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......그런가?","JPN":"……そうだろうか？","ENG":"Is that so?","TWN":"……是嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"쓸데없는 걱정이라고 생각하지만...... 뭐, 알겠다.","JPN":"余計な心配だと判断するが……まあ、わかった。","ENG":"I would say you worry over nothing... but very well.","TWN":"雖然是妳無謂的擔心……算了，我知道了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그보다 지내는 건 어때? 불편한 점은 없나?","JPN":"それより調子はどうだ？　不便なところはないか？","ENG":"Anyway, how are you getting along here? Everything comfortable enough for you?","TWN":"話說回來，妳過得怎麼樣？有什麼不方便的嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그다지.","JPN":"とくには。","ENG":"More or less.","TWN":"沒什麼特別的地方。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"구속구가 좀 거추장스럽긴 하지만, 큰 문제는 없다.","JPN":"拘束装置が少し邪魔だが、大した問題ではない。","ENG":"The restraints are rather inconvenient, but it’s bearable enough.","TWN":"雖然拘留所挺煩人的，但是問題不大。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다행이군. 그래도 조심하라고.","JPN":"それはよかった。でも、気をつけろよ。","ENG":"Good. Still, be careful.","TWN":"那就好。但妳還是要小心點。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"괜히 힘으로 풀려고 했다간 내장되어 있는 폭탄이 터질 거다.","JPN":"下手に力で解こうとしたら、内蔵爆弾が爆発するだろうから。","ENG":"If you try to force them loose, you’ll set off the internal explosives.","TWN":"如果妳想要用蠻力逃脫的話，內藏的炸彈就會引爆。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"피차 지저분한 꼴은 보고 싶지 않겠지?","JPN":"お互い、汚らわしい姿は見たくないだろう？","ENG":"Neither of us would want to deal with that mess, right?","TWN":"我們彼此都不想看到這種可怕的情況吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......알겠다. 기억해 두지.","JPN":"……わかった。記録する。","ENG":"...Understood. I’ll keep that in mind.","TWN":"……我知道。我會記住的。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그래서 용건은 뭐지?","JPN":"さて、用件は何？","ENG":"So what is the purpose of your visit?","TWN":"不過妳是來做什麼的？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"설마 내 처우개선을 위해 여기까지 온 건 아닐 텐데.","JPN":"まさか私の処遇改善のために\\nここまで来たわけではないだろうし……","ENG":"I hardly think you came to check in on my welfare during captivity.","TWN":"總不會是為了來改善我的待遇吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건 내가 묻고 싶은 질문이로군.","JPN":"それはこっちが聞きたいことだ。","ENG":"I was about to ask you the same question.","TWN":"這才是我想問的問題呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"항복이라니, 그런 헛소리를 정말 믿을 거라고 생각한 건 아니겠지?","JPN":"降参なんて、そんなたわ言を本気で信じると思ってないだろうな？","ENG":"You don’t really expect us to believe you've surrendered in earnest, do you?","TWN":"妳不會以為我真的會相信投降這種鬼話吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};